class Solution:
    def reformatNumber(self, number: str) -> str:
        number = number.replace(" ", "").replace("-", "")
        result = []
        while number:
            if len(number) > 3:
                result.append(number[:3])
                number = number[3:]
            elif len(number) == 2:
                result.append(number)
                number = ""
            else:
                result.append(number)
                number = ""
        return "-".join(result)
